import{_ as e,c as o,o as l,R as t}from"./chunks/framework.CIzs38F0.js";const c=JSON.parse('{"title":"1.Volume的功能","description":"","frontmatter":{},"headers":[],"relativePath":"guide/container/k8s/存储/Volume/1-volume.md","filePath":"guide/container/k8s/存储/Volume/1-volume.md","lastUpdated":1714030813000}'),a={name:"guide/container/k8s/存储/Volume/1-volume.md"},i=t('<h1 id="_1-volume的功能" tabindex="-1">1.Volume的功能 <a class="header-anchor" href="#_1-volume的功能" aria-label="Permalink to &quot;1.Volume的功能&quot;">​</a></h1><p>1.Volume是Pod中能够被多个容器访问的共享目录，可以让容器的数据写到宿主机上或者写文件到网络存储中</p><p>2.可以实现容器配置文件集中化定义与管理，通过ConfigMap资源对象来实现.</p><h1 id="_2-volume的特点" tabindex="-1">2.Volume的特点 <a class="header-anchor" href="#_2-volume的特点" aria-label="Permalink to &quot;2.Volume的特点&quot;">​</a></h1><p>k8s中的Volume与Docker的Volume相似，但不完全相同。</p><ol><li>k8s上Volume定义在Pod上，然后被一个Pod中的多个容器挂载到具体的文件目录下。</li><li>k8s的Volume与Pod生命周期相关而不是容器是生命周期，即容器挂掉，数据不会丢失但是Pod挂掉，数据则会丢失。</li><li>k8s中的Volume支持多种类型的Volume：Ceph、GlusterFS等分布式系统</li></ol><h1 id="_3-volume的使用方式" tabindex="-1">3.Volume的使用方式 <a class="header-anchor" href="#_3-volume的使用方式" aria-label="Permalink to &quot;3.Volume的使用方式&quot;">​</a></h1><p>先在Pod上声明一个Volume，然后容器引用该Volume并Mount到容器的某个目录</p><h2 id="_3-1volume类型" tabindex="-1">3.1Volume类型 <a class="header-anchor" href="#_3-1volume类型" aria-label="Permalink to &quot;3.1Volume类型&quot;">​</a></h2><h3 id="emptydir" tabindex="-1">emptyDir <a class="header-anchor" href="#emptydir" aria-label="Permalink to &quot;emptyDir&quot;">​</a></h3><p>emptyDir Volume是在Pod分配到Node时创建的，初始内容为空，无须指定宿主机上对应的目录文件，由K8S自动分配一个目录，当Pod被删除时，对应的emptyDir数据也会永久删除</p><p><strong>作用</strong>：</p><ol><li>临时空间，例如程序的临时文件，无须永久保留</li><li>长时间任务的中间过程CheckPoint的临时保存目录</li><li>一个容器需要从另一个容器中获取数据的目录（即多容器共享目录）</li></ol><blockquote><p>目前用户无法设置emptyVolume的使用介质，如果kubelet的配置使用硬盘则emptyDir将创建在该硬盘上</p></blockquote><h3 id="hostpath" tabindex="-1">hostPath <a class="header-anchor" href="#hostpath" aria-label="Permalink to &quot;hostPath&quot;">​</a></h3><p>hostPath是在Pod上挂载宿主机上的文件或目录</p><p><strong>作用</strong>：</p><ol><li>容器应用日志需要持久化时，可以使用宿主机的高速文件系统进行存储</li><li>需要访问宿主机上Docker引擎内部数据结构的容器应用时，可以通过定义hostPath为宿主机/var/lib/docker目录，使容器内部应用可以直接访问Docker的文件系统</li></ol><blockquote><p>1.在不同的Node上具有相同配置的Pod可能会因为宿主机上的目录或文件不同导致对Volume上目录或文件的访问结果不一致。</p><p>2.如果使用了资源配额管理，则kubernetes无法将hostPath在宿主机上使用的资源纳入管理</p></blockquote><h3 id="gcepersistentdisk" tabindex="-1">gcePersistentDisk <a class="header-anchor" href="#gcepersistentdisk" aria-label="Permalink to &quot;gcePersistentDisk&quot;">​</a></h3><p>表示使用谷歌公有云提供的永久磁盘（Persistent Disk ,PD）存放Volume的数据，它与EmptyDir不同，PD上的内容会被永久保存。当Pod被删除时，PD只是被卸载时，但不会被删除。需要先创建一个永久磁盘，才能使用gcePersistentDisk。</p><p>使用gcePersistentDisk的限制条件：</p><ul><li>Node(运行kubelet的节点)需要是GCE虚拟机。</li><li>虚拟机需要与PD存在于相同的GCE项目中和Zone中</li></ul><h1 id="_4-persistent-volume" tabindex="-1">4.Persistent Volume <a class="header-anchor" href="#_4-persistent-volume" aria-label="Permalink to &quot;4.Persistent Volume&quot;">​</a></h1><p>Volume定义在Pod上，属于“计算资源”的一部分，而Persistent Volume和Persistent Volume Claim是网络存储，简称PV和PVC，可以理解为k8s集群中某个网络存储中对应的一块存储</p><ul><li>PV是网络存储，不属于任何Node，但可以在每个Node上访问。</li><li>PV不是定义在Pod上，而是独立于Pod之外定义。</li><li>PV常见类型：GCE Persistent Disks、NFS、RBD等。</li></ul><p>PV是有状态的对象，状态类型如下：</p><ul><li>Available:空闲状态</li><li>Bound:已经绑定到某个PVC上</li><li>Released:对应的PVC已经删除，但资源还没有回收</li><li>Failed:PV自动回收失败</li></ul>',28),s=[i];function r(u,n,m,d,h,p){return l(),o("div",null,s)}const V=e(a,[["render",r]]);export{c as __pageData,V as default};
